"""런타임 - 세션 다시 시작"""

from google.colab import files
uploaded = files.upload()
#

from paddleocr import PaddleOCR
import os

image_path = "20240825_085438.jpg" #사진 파일명으로 바꿀것

ocr = PaddleOCR(
    lang='korean', #한글, 영어, 숫자 인식에 특화
    text_recognition_model_name='korean_PP-OCRv5_mobile_rec', #한글 특화 모델 사용
    use_doc_orientation_classify=False,
    use_doc_unwarping=False,
    use_textline_orientation=False,
    text_det_limit_side_len=1536,   # 이미지 변 길이 옵션. 기본값 960보다 크게
    text_det_limit_type='max'
)

result = ocr.predict(image_path)

boxes = []
texts = []
scores = []

for page in result:
    if 'dt_polys' in page:
        boxes.extend(page['dt_polys']) # 추출한 박스 번호
    if 'rec_texts' in page:
        texts.extend(page['rec_texts']) # 추출한 글씨
    if 'rec_scores' in page:
        scores.extend(page['rec_scores']) # 추출한 글씨에 대한 신뢰도

for b, t, s in zip(boxes, texts, scores):
    print(f"인식한 박스의 위치 {b}" )
    print(f"인식한 텍스트 : {t}   (신뢰도={s:.3f})")
    print("-------------------------------")

"""PaddleOCR의 파라미터 소개


1. thresh : PaddleOCR이 픽셀마다 글자에 해당할 가능성을 내놓는데, thresh는 기준치가 된다. thresh를 낮추면 더 많은 영역들이 글자로써 처리된다. 작은 글씨, 흐릿한 글씨들을 놓치지 않을 수 있으나, 잡음이 생기게 된다. 기본값은 0.3으로 설정되어있다.


2. box_thresh : PaddleOCR이 인식한 박스들 중 살릴지 버릴지에 대한 confidence 기준. 낮추면 확신이 약한 박스도 남고, 높이면 강하게 확신하는 박스만 남는다. 기본값은 0.6


3. unclip_ratio : 검출된 텍스트 영역의 박스를 얼마나 확장할지. 키우면 박스가 더 넉넉해져 잘림 문제가 해결되지만 잡음이 섞일 수 있다. 낮추면 박스가 더 타이트해져 깔끔할 수는 있지만 글자 일부가 잘릴 수 있다. 기본값은 1.5


4. text_det_limit_side_len : 텍스트 detection 전에, 이미지를 리사이즈할 때 기준이 되는 변 길이. 키우면 작은 글씨를 더 잘 인식하지만 메모리 소모가 커진다.


5. limit_type : 4번의 limit_side_len을 짧은 변에 적용할지, 긴 변에 적용할지 정한다. min으로 설정하면 짧은 변이 limit_side_len보다 작지 않게 보정. max로 설정하면 긴 변이 limit_side_len보다 크지 않게 보정.


6. max_side_limit : 이미지 변 최대 한도


7. use_doc_orientation_classify : 사진 전체가 몇 도 돌아가 있는지 판별
use_doc_unwarping : 사진의 휘어짐, 왜곡, 구김을 펴주는 옵션
use_textline_orientation : 뒤집힌 텍스트가 있거나 캡쳐나 조각 이미지 등이 섞인 특수 상황

"""

#원본 텍스트 데이터 저장

import json

ocr_items = []

for i, (box, text, score) in enumerate(zip(boxes, texts, scores), start=1):
    ocr_items.append({
        "id": i,
        "text": text,
        "score": float(score),
        "box": box.tolist() if hasattr(box, "tolist") else box # box에 들어있는게 그냥 행렬이 아니라 넘파이행렬이면 리스트에 바로 넣으면 오류가 날 수 있으니 그걸 처리하는 과정이다.
        #tolist : 넘파이를 일반 행렬로
    })

raw_result = {
    "image_path": image_path,
    "ocr_result": ocr_items
}

with open("receipt_ocr_raw.json", "w", encoding="utf-8") as f:
    json.dump(raw_result, f, ensure_ascii=False, indent=2) #json.dump : json 형식으로 바로 저장하는거다. / json.dumps라면 문자열로 바꿔 저장하는거다. 주의할것.
#indent : 보기좋게 들여쓰기

print("저장 완료: receipt_ocr_raw.json")

